"use client";

import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";

export default function CounterweightAction() {
  const [ready, setReady] = useState(false);
  const reduced = useReducedMotion();
  return <div className="grid min-h-56 place-items-center rounded-[22px] bg-[#f4f5f6] p-5"><div className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><motion.button type="button" onClick={() => setReady(!ready)} whileHover={reduced ? undefined : { y: -2 }} whileTap={reduced ? undefined : { y: 1 }} transition={{ duration: .18 }} className="relative flex min-h-12 w-full items-center overflow-hidden rounded-2xl bg-[#111] px-4 text-left text-sm font-extrabold text-white outline-offset-4 focus-visible:outline focus-visible:outline-2 focus-visible:outline-[#111]" aria-pressed={ready}><motion.span animate={{ x: ready ? 0 : 132 }} transition={reduced ? { duration: .12 } : { type: "spring", stiffness: 360, damping: 27 }} className="absolute right-3 h-7 w-7 rounded-full bg-[#53e8d4]"/><motion.span animate={{ opacity: ready ? 0 : 1 }} transition={{ duration: .16 }}>Review changes</motion.span><motion.span animate={{ opacity: ready ? 1 : 0 }} transition={{ duration: .16 }} className="absolute">Ready to publish</motion.span></motion.button><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{ready ? "All checks are balanced." : "Choose when your review is complete."}</p></div></div>;
}
